// Extract selected clients from webhook payload
// When triggered via webhook, use the payload clients array
// When triggered via schedule, this node is bypassed — schedule trigger reads from Google Sheets directly

const body = $input.first().json.body || $input.first().json;
const clients = body.clients || [];
const month = body.month || '';
const triggeredBy = body.triggered_by || 'schedule';

return clients.map(client => ({
  json: {
    client_name: client.client_name,
    payment_method: client.payment_method,
    ar_email: client.ar_email,
    manual_attachment: client.manual_attachment,
    month: month,
    triggered_by: triggeredBy
  }
}));
